<?php require_once __DIR__ . '/app/auth.php'; require_login(); csrf_check(); $pdo=db(); if($_SERVER['REQUEST_METHOD']==='POST'){ $id=(int)($_POST['id']??0); if(($_POST['action']??'')==='save'){ $data=[trim($_POST['name']),trim($_POST['speed']),(int)$_POST['price'],isset($_POST['is_active'])?1:0]; if($id){$data[]=$id;$pdo->prepare('UPDATE packages SET name=?,speed=?,price=?,is_active=? WHERE id=?')->execute($data);} else {$pdo->prepare('INSERT INTO packages(name,speed,price,is_active) VALUES(?,?,?,?)')->execute($data);} } redirect('packages.php'); } require_once __DIR__ . '/app/layout.php'; $edit=null; if(isset($_GET['edit'])){$st=$pdo->prepare('SELECT * FROM packages WHERE id=?');$st->execute([(int)$_GET['edit']]);$edit=$st->fetch();} $rows=$pdo->query('SELECT * FROM packages ORDER BY is_active DESC, price ASC')->fetchAll(); render_header('Paket Internet'); ?>
<div class="grid-2"><div class="card"><div class="panel-title"><h2>Master Paket</h2></div><div class="table-wrap"><table class="responsive"><thead><tr><th>Nama</th><th>Speed</th><th>Harga</th><th>Status</th><th>Aksi</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td data-label="Nama"><b><?=e($r['name'])?></b></td><td data-label="Speed"><?=e($r['speed'])?></td><td data-label="Harga"><?=rupiah($r['price'])?></td><td data-label="Status"><span class="pill <?=$r['is_active']?'green':'red'?>"><?=$r['is_active']?'Aktif':'Nonaktif'?></span></td><td data-label="Aksi"><a class="btn soft xs" href="packages.php?edit=<?=$r['id']?>">Edit</a></td></tr><?php endforeach;?></tbody></table></div></div><form class="card form-card" method="post"><input type="hidden" name="csrf" value="<?=e(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=e($edit['id']??0)?>"><div class="panel-title"><h2><?=$edit?'Edit':'Tambah'?> Paket</h2></div><div class="form-grid"><div class="field"><label>Nama Paket</label><input name="name" required value="<?=e($edit['name']??'')?>"></div><div class="field"><label>Kecepatan</label><input name="speed" required value="<?=e($edit['speed']??'')?>"></div><div class="field"><label>Harga</label><input name="price" type="number" required value="<?=e($edit['price']??'')?>"></div><div class="field"><label>Status</label><label class="flex gap-2 items-center mt-3"><input type="checkbox" name="is_active" <?=(!$edit||$edit['is_active'])?'checked':''?>> Aktif</label></div></div><button class="btn primary mt-5" type="submit">Simpan Paket</button></form></div><?php render_footer(); ?>
